import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.BPmc_f4o.js";const g=JSON.parse('{"title":"How to Use ngrok","description":"","frontmatter":{},"headers":[],"relativePath":"howto/ngrok.md","filePath":"howto/ngrok.md"}'),n={name:"howto/ngrok.md"};function i(r,e,p,l,d,h){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="how-to-use-ngrok" tabindex="-1">How to Use ngrok <a class="header-anchor" href="#how-to-use-ngrok" aria-label="Permalink to &quot;How to Use ngrok&quot;">​</a></h1><p><a href="https://ngrok.com/" target="_blank" rel="noreferrer">ngrok</a> allows you to serve your dev environment on the public internet. This may sound like a Bad Idea, but it&#39;s useful to testing webhooks or demoing what you are working on.</p><p>To server your Brut app on ngrok:</p><ol><li><p>Sign up for ngrok - you can do everything here witih the free plan.</p></li><li><p>Get your authtoken, which is available <a href="https://dashboard.ngrok.com/get-started/your-authtoken" target="_blank" rel="noreferrer">from the Dashboard</a>.</p></li><li><p>Stop your dev environment and edit <code>Dockerfile.dx</code> to install ngrok. Locate the section that sets up the local user. There is a large comment explaining this and the first directive will be something like <code>ARG user_uid=xxxxx</code>. <strong>Before</strong> this directive, add (this is based on <a href="https://dashboard.ngrok.com/get-started/setup/linux" target="_blank" rel="noreferrer">ngrok&#39;s documentation</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RUN curl -sSL https://ngrok-agent.s3.amazonaws.com/ngrok.asc | \\</span></span>
<span class="line"><span>      tee /etc/apt/trusted.gpg.d/ngrok.asc &gt;/dev/null &amp;&amp; \\</span></span>
<span class="line"><span>    echo &quot;deb https://ngrok-agent.s3.amazonaws.com bookworm main&quot; | \\</span></span>
<span class="line"><span>      tee /etc/apt/sources.list.d/ngrok.list &amp;&amp; \\</span></span>
<span class="line"><span>    apt update &amp;&amp; \\</span></span>
<span class="line"><span>    apt install --yes ngrok</span></span></code></pre></div></li><li><p>Rebuild your dev environment with <code>dx/build</code>.</p></li><li><p>Start your dev environment and set up your app:</p><ol><li><code>dx/start</code></li><li>[in another termianl] <code>dx/exec bin/setup</code></li></ol></li><li><p>Make your authtoken available inside your docker container</p><ol><li><code>dx/exec ngrok config add-authtoken &lt;&lt;YOUR_AUTHTOKEN&gt;&gt;</code></li></ol></li><li><p>Add this line to <code>Procfile.development</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ngrok: ngrok http 6502</span></span></code></pre></div></li><li><p>Allow ngrok&#39;s domain to be served. In <code>app/src/app.rb</code>, find the <code>initialize</code> method of <code>App</code> and add this at the end:</p><div class="language-ruby vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ruby</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Brut</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">container</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">override</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;local_hostname&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;.ngrok-free.dev&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li></ol><p>Now, when you run <code>dx/exec bin/dev</code> your app is on the public internet. Go to the (confusingly titled) <a href="https://dashboard.ngrok.com/agents" target="_blank" rel="noreferrer">Agents page</a> to see your app. You&#39;ll need to click into it to find the URL.</p><p>To always use that URL, modify <code>Procfile.development</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ngrok: ngrok http 6502 --url &lt;&lt;whatever that url was&gt;&gt;&gt;</span></span></code></pre></div><p>Brut doesn&#39;t provide more automation than this, but you can make this easier by modifying <code>bin/setup</code> as needed.</p>`,8)])])}const k=t(n,[["render",i]]);export{g as __pageData,k as default};
